import React, { useMemo } from "react";

interface CategoryViewProps {
  searchTerm: string;
  dateFilter: string;
}

const CategoryView: React.FC<CategoryViewProps> = ({ searchTerm, dateFilter }) => {
  const allCategories = [
    {
      id: 'imported',
      title: 'Fichiers Importés',
      icon: 'fa-download text-blue-500',
      color: 'bg-blue-50 dark:bg-blue-900/20 border-blue-200 dark:border-blue-800',
      items: [
        { name: 'audio_001.mp3', date: '2025-01-15', size: '5.2 MB' },
        { name: 'audio_002.mp3', date: '2025-01-15', size: '3.8 MB' },
        { name: 'scan_chapitre1.pdf', date: '2025-01-14', size: '2.1 MB' },
      ]
    },
    {
      id: 'transcribed',
      title: 'Transcrits',
      icon: 'fa-file-lines text-green-500',
      color: 'bg-green-50 dark:bg-green-900/20 border-green-200 dark:border-green-800',
      items: [
        { name: 'Transcription A', date: '2025-01-15', size: '-' },
        { name: 'Transcription B', date: '2025-01-14', size: '-' },
      ]
    },
    {
      id: 'book-projects',
      title: 'Projets de Livre',
      icon: 'fa-book text-purple-500',
      color: 'bg-purple-50 dark:bg-purple-900/20 border-purple-200 dark:border-purple-800',
      items: [
        { name: 'Livre 1', date: '2025-01-15', size: '-' },
      ]
    },
    {
      id: 'proofreading',
      title: 'Relectures',
      icon: 'fa-eye text-amber-500',
      color: 'bg-amber-50 dark:bg-amber-900/20 border-amber-200 dark:border-amber-800',
      items: [
        { name: 'Relecture 1 - Livre 1', date: '2025-01-15', size: '-' },
        { name: 'Relecture 2 - Livre 1', date: '2025-01-15', size: '-' },
      ]
    },
  ];

  // ✅ FILTRAGE
  const filteredCategories = useMemo(() => {
    return allCategories.map((category) => ({
      ...category,
      items: category.items.filter((item) => {
        const matchesSearch = item.name.toLowerCase().includes(searchTerm.toLowerCase());
        let matchesDate = true;
        
        if (dateFilter === "today") {
          matchesDate = item.date === new Date().toISOString().split('T')[0];
        } else if (dateFilter === "week") {
          const weekAgo = new Date();
          weekAgo.setDate(weekAgo.getDate() - 7);
          matchesDate = new Date(item.date) >= weekAgo;
        } else if (dateFilter === "month") {
          const monthAgo = new Date();
          monthAgo.setMonth(monthAgo.getMonth() - 1);
          matchesDate = new Date(item.date) >= monthAgo;
        }
        
        return matchesSearch && matchesDate;
      })
    })).filter((category) => category.items.length > 0 || searchTerm === "");
  }, [searchTerm, dateFilter]);

  const totalItems = filteredCategories.reduce((acc, cat) => acc + cat.items.length, 0);

  return (
    <div className="space-y-6">
      <h2 className="text-lg font-semibold text-gray-900 dark:text-white flex items-center justify-between">
        <div className="flex items-center">
          <i className="fas fa-folder mr-2 text-purple-600"></i>
          Vue par Rubriques
        </div>
        <span className="text-sm text-gray-500 dark:text-gray-400">
          {totalItems} élément{totalItems > 1 ? 's' : ''}
        </span>
      </h2>
      
      {filteredCategories.length === 0 ? (
        <div className="text-center py-16">
          <i className="fas fa-search text-4xl text-gray-400 mb-4"></i>
          <p className="text-gray-600 dark:text-gray-400">Aucun résultat ne correspond aux filtres</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {filteredCategories.map((category) => (
            <div
              key={category.id}
              className={`rounded-lg border p-4 ${category.color}`}
            >
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-3">
                  <i className={`fas ${category.icon} text-2xl`}></i>
                  <div>
                    <h3 className="font-semibold text-gray-900 dark:text-white">
                      {category.title}
                    </h3>
                    <p className="text-sm text-gray-600 dark:text-gray-400">
                      {category.items.length} fichier{category.items.length > 1 ? 's' : ''}
                    </p>
                  </div>
                </div>
                <button className="px-3 py-1.5 text-xs bg-white dark:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-lg hover:shadow transition-all">
                  Voir tout
                </button>
              </div>
              
              <div className="space-y-2">
                {category.items.map((item, index) => (
                  <div
                    key={index}
                    className="flex items-center justify-between p-2 bg-white dark:bg-gray-800 rounded-lg"
                  >
                    <span className="text-sm text-gray-700 dark:text-gray-300">
                      {item.name}
                    </span>
                    <span className="text-xs text-gray-500 dark:text-gray-400">
                      {item.date}
                    </span>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default CategoryView;
